import { useDisclosure, VStack } from '@chakra-ui/react';
import { FilterIcon } from '@ui/assets/icons/FilterIcon';
import { Button } from '@ui/components/Button';
import { SideDrawer } from '@ui/components/templates/SideDrawer';
import { useLocalStorageState } from '@ui/utils/useLocalStorageState';
import { FormProvider } from 'react-hook-form';
import { useTranslation } from 'react-i18next';
import { SearchTermFilter } from './components/SearchTermFilter';
import { StatusFilter } from './components/StatusFilter';
import { TagsFilter } from './components/TagsFilter';
import { useActionPagesFilterForm } from './hooks/useActionPagesFilterForm';

const formId = 'action-pages-table-filter-form';

export const FilterDrawer = () => {
  const { activeFilterCount, form, onClear, onRestore, onSubmit } = useActionPagesFilterForm();
  const { isOpen, onClose, onToggle } = useDisclosure({ onOpen: onRestore });
  const { t } = useTranslation('actionPages', { keyPrefix: 'filter' });
  const { t: tCommon } = useTranslation('common');
  const [isPinned, setIsPinned] = useLocalStorageState('action-pages-filter-drawer-pinned', false);

  return (
    <>
      <Button
        isActive={!!activeFilterCount}
        leftIcon={<FilterIcon />}
        onClick={onToggle}
        variant="tertiary"
      >
        {tCommon('button.filter')} {!!activeFilterCount && `(${activeFilterCount})`}
      </Button>

      <FormProvider {...form}>
        <SideDrawer
          headerIcon={<FilterIcon />}
          isOpen={isOpen}
          isPinned={isPinned}
          onChangePinned={setIsPinned}
          onClose={() => {
            onRestore();
            onClose();
          }}
          primaryAction={{
            children: tCommon('button.applyFilters'),
            form: formId,
          }}
          secondaryAction={{
            children: tCommon('button.clearFilters'),
            onClick: onClear,
          }}
          title={t('heading')}
        >
          <form autoComplete="off" id={formId} onSubmit={onSubmit}>
            <VStack alignItems="stretch" spacing={6}>
              <SearchTermFilter />
              <TagsFilter />
              <StatusFilter />
            </VStack>
          </form>
        </SideDrawer>
      </FormProvider>
    </>
  );
};

